/* ---------------------------------------------------------
   Hooks
--------------------------------------------------------- */

function usePrefersReducedMotion() {
  const [reduced, setReduced] = useState(false);
  useEffect(() => {
    const mq = window.matchMedia("(prefers-reduced-motion: reduce)");
    setReduced(mq.matches);
    const handler = (e) => setReduced(e.matches);
    mq.addEventListener("change", handler);
    return () => mq.removeEventListener("change", handler);
  }, []);
  return reduced;
}

function useReveal() {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setVisible(true);
            io.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.15, rootMargin: "0px 0px -40px 0px" }
    );
    io.observe(el);
    return () => io.disconnect();
  }, []);
  return [ref, visible];
}

function Reveal({ children, as: Tag = "div", delay = 0, className = "" }) {
  const [ref, visible] = useReveal();
  return (
    <Tag
      ref={ref}
      className={`reveal ${visible ? "reveal-visible" : ""} ${className}`}
      style={{ transitionDelay: visible ? `${delay}ms` : "0ms" }}
    >
      {children}
    </Tag>
  );
}

/* ---------------------------------------------------------
   Terminal boot hero
--------------------------------------------------------- */

const BOOT_LINES = [
  { prompt: "arwin@backend", cmd: "whoami" },
  { output: "ARWIN_MADEJA" },
  { prompt: "arwin@backend", cmd: "systemctl status role" },
  { output: "● backend-developer-intern.service — active (running)" },
];

function TerminalHero({ reducedMotion }) {
  const [lineIndex, setLineIndex] = useState(reducedMotion ? BOOT_LINES.length : 0);
  const [charIndex, setCharIndex] = useState(reducedMotion ? 999 : 0);
  const [done, setDone] = useState(reducedMotion);

  useEffect(() => {
    if (reducedMotion) return;
    if (lineIndex >= BOOT_LINES.length) {
      setDone(true);
      return;
    }
    const current = BOOT_LINES[lineIndex];
    const text = current.cmd ?? current.output;
    if (current.cmd === undefined) {
      const t = setTimeout(() => {
        setLineIndex((i) => i + 1);
        setCharIndex(0);
      }, 260);
      return () => clearTimeout(t);
    }
    if (charIndex <= text.length) {
      const t = setTimeout(() => setCharIndex((c) => c + 1), 28);
      return () => clearTimeout(t);
    } else {
      const t = setTimeout(() => {
        setLineIndex((i) => i + 1);
        setCharIndex(0);
      }, 220);
      return () => clearTimeout(t);
    }
  }, [lineIndex, charIndex, reducedMotion]);

  return (
    <div className="terminal">
      <div className="terminal-chrome">
        <span className="dot dot-r" />
        <span className="dot dot-y" />
        <span className="dot dot-g" />
        <span className="terminal-title">arwin@backend:~</span>
      </div>
      <div className="terminal-body">
        {BOOT_LINES.map((line, i) => {
          if (i > lineIndex) return null;
          if (line.cmd !== undefined) {
            const shown = i === lineIndex ? line.cmd.slice(0, charIndex) : line.cmd;
            return (
              <div className="term-line" key={i}>
                <span className="term-prompt">{line.prompt}$</span>
                <span className="term-cmd">
                  {" "}
                  {shown}
                  {i === lineIndex && !done && <span className="caret" />}
                </span>
              </div>
            );
          }
          return (
            <div className="term-line term-output" key={i}>
              {line.output}
            </div>
          );
        })}
        {done && (
          <div className="term-final">
            <div className="term-final-name">ARWIN MADEJA</div>
            <div className="term-final-role">{CONTACT.role}</div>
          </div>
        )}
      </div>
    </div>
  );
}

