/* ---------------------------------------------------------
   Certificate card + Lightbox
--------------------------------------------------------- */

function CertThumb({ item, onOpen }) {
  return (
    <button className="cert-thumb" onClick={() => onOpen(item)}>
      <img src={item.image} alt={item.name} loading="lazy" />
      <div className="cert-thumb-overlay">
        <Maximize2 size={16} />
        <span>view certificate</span>
      </div>
    </button>
  );
}

function Lightbox({ item, onClose }) {
  const [closing, setClosing] = useState(false);

  const handleClose = () => {
    setClosing(true);
    setTimeout(onClose, 170);
  };

  useEffect(() => {
    function onKey(e) {
      if (e.key === "Escape") handleClose();
    }
    window.addEventListener("keydown", onKey);
    document.body.style.overflow = "hidden";
    return () => {
      window.removeEventListener("keydown", onKey);
      document.body.style.overflow = "";
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (!item) return null;

  return (
    <div className={`lightbox-backdrop ${closing ? "is-closing" : "is-opening"}`} onClick={handleClose}>
      <div className={`lightbox-panel ${closing ? "is-closing" : "is-opening"}`} onClick={(e) => e.stopPropagation()}>
        <button className="lightbox-close" onClick={handleClose} aria-label="Close">
          <X size={18} />
        </button>
        <img src={item.image} alt={item.name} className="lightbox-img" />
        <div className="lightbox-caption">
          <div className="lightbox-name">{item.name}</div>
          <div className="lightbox-issuer">{item.issuer}</div>
        </div>
      </div>
    </div>
  );
}

